package exporter

import (
	"github.com/nightona-co/nightona/libs/common-go/pkg/envcompat"
)

// The collector binary is generated by the OpenTelemetry Collector Builder,
// so there is no main() under our control. Aliasing legacy DAYTONA_* env vars
// in init() guarantees it runs before the collector resolves ${env:...}
// references in its configuration.
func init() {
	envcompat.ApplyLegacyEnvAliases()
}
